22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const BLOCK_SIZE = 3;
28	const BLOCK_PRICE = 60;
29	const COMPONENT_TYPES = ["rune", "moonstone"];
30	const LOYALTY_YEARS_THRESHOLD = 2;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	function basePremiumFor(item: ItemSpec): number {
44	  return BASE_PREMIUMS[item.type] ?? 0;
45	}
46	
47	function sumBasePremiums(items: ItemSpec[]): number {
48	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
49	}
50	
51	function countItemsOfType(items: ItemSpec[], type: string): number {
52	  return items.filter((item) => item.type === type).length;
53	}
54	
55	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
56	  const count = countItemsOfType(items, componentType);
57	  if (count !== BLOCK_SIZE) return 0;
58	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
59	}
60	
61	function blockAdjustment(items: ItemSpec[]): number {
62	  return COMPONENT_TYPES.reduce(
63	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
64	    0
65	  );
66	}
67	
68	function isHighlyEnchanted(item: ItemSpec): boolean {
69	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
70	}
71	
72	function itemSurchargeFor(item: ItemSpec): number {
73	  let surcharge = 0;
74	  if (item.cursed) surcharge += basePremiumFor(item) * CURSE_SURCHARGE_RATE;
75	  if (isHighlyEnchanted(item)) surcharge += basePremiumFor(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
76	  return surcharge;
77	}
78	
79	function sumItemSurcharges(items: ItemSpec[]): number {
80	  return items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
81	}
82	
83	function qualifiesForLoyaltyDiscount(customer: Customer): boolean {
84	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
85	}
86	
87	function loyaltyDiscountFor(customer: Customer, policyBasePremium: number): number {
88	  if (!qualifiesForLoyaltyDiscount(customer)) return 0;
89	  return policyBasePremium * LOYALTY_DISCOUNT_RATE;
90	}
91	
92	function followUpDiscountFor(customer: Customer, policyBasePremium: number): number {
93	  if ((customer.previousContracts ?? 0) <= 0) return 0;
94	  return policyBasePremium * FOLLOW_UP_DISCOUNT_RATE;
95	}
96	
97	export function quote(input: QuoteInput): QuoteResult {
98	  const items = input.items;
99	  const policyBasePremium = sumBasePremiums(items) + blockAdjustment(items);
100	  const itemSurcharges = sumItemSurcharges(items);
101	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
102	  const loyaltyDiscount = loyaltyDiscountFor(input.customer, policyBasePremium);
103	  const followUpDiscount = followUpDiscountFor(input.customer, policyBasePremium);
104	  return {
105	    premium: Math.ceil(
106	      policyBasePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE
107	    ),
108	  };
109	}
110	
111	export function claim(): unknown {
112	  return undefined;
113	}
